parameters.jsonSchema:
{
  "type": "object",
  "properties": {
    "merchant_cleaned": {
      "type": "string",
      "description": "The clean name of the brand or store."
    },
    "reasoning": {
      "type": "string",
      "description": "Short explanation of the business and why the category was chosen."
    },
    "category": {
      "type": "string",
      "enum": [
        "Groceries",
        "Health",
        "Transport",
        "Dining",
        "Utilities",
        "Shopping",
        "Entertainment",
        "Other"
      ]
    },
    "currency": {
      "type": "string",
      "description": "The standard 3-letter ISO currency code (e.g., PLN, EUR, USD) found in the text or inferred from the country."
    }
  },
  "required": ["merchant_cleaned", "reasoning", "category", "currency"]
}

parameters.jsCode:
const items = $input.all();

for (const item of items) {
  const payload = item.json.body || item.json;
  const bodyText = payload.notificationBody || "";

  const amountMatch = bodyText.match(/[\d]+[.,][\d]{2}/);
  item.json.extractedAmount = amountMatch ? parseFloat(amountMatch[0].replace(',', '.')) : null;
}

return items;
